local OldToNew = {}
local NewToOld = {}
local DressToNew = {}
local DressToOld = {}

local EnchantmentList = {}
local PotionEffect = {}

local function init()
    local config = FileUtil.getConfigFromCsv("setting/ItemMapping.csv", 2, true)
    for _, item in pairs(config) do
        local newIds = OldToNew[item.ItemId] or {}
        table.insert(newIds, tonumber(item.NewItemId))
        OldToNew[item.ItemId] = newIds
        NewToOld[item.NewItemId] = tonumber(item.ItemId)
        DressToNew[item.ItemId .. "#" .. item.DressItemId] = tonumber(item.NewItemId)
        local oldIds = DressToOld[item.DressItemId] or {}
        table.insert(oldIds, tonumber(item.ItemId))
        DressToOld[item.DressItemId] = oldIds
    end

    config = FileUtil.getConfigFromCsv("setting/ItemEnchantment.csv", 2, true)
    for _, item in pairs(config) do
        EnchantmentList[item.Id] = { tonumber(item.EnchantId), tonumber(item.EnchantLevel) }
    end

    config = FileUtil.getConfigFromCsv("setting/ItemPotionEffect.csv", 2, true)
    for _, item in pairs(config) do
        PotionEffect[item.ItemId] = {
            Type = tonumber(item.Type),
            Level = tonumber(item.Level),
            Duration = tonumber(item.Duration)
        }
    end
end

init()

ItemMapping = {}

function ItemMapping:getNewItemIds(itemId)
    return OldToNew[tostring(itemId)] or {}
end

function ItemMapping:getOldItemId(itemId)
    return NewToOld[tostring(itemId)] or itemId
end

function ItemMapping:getItemIdByDressId(itemId, dressId)
    return DressToNew[tostring(itemId) .. "#" .. tostring(dressId)] or itemId
end

function ItemMapping:getOldItemIdsByDressId(dressId)
    return DressToOld[tostring(dressId)] or {}
end

ItemEnchantment = {}

function ItemEnchantment:getEnchantmentList(enchantIds)
    local enchantList = {}
    for _, enchantId in pairs(enchantIds) do
        local enchant = EnchantmentList[enchantId]
        if enchant then
            table.insert(enchantList, enchant)
        end
    end
    return enchantList
end

function ItemEnchantment:getItemEnchantmentList(inventory, index)
    local enchantList = {}
    local enchantCount = inventory:getItemStackEnchantmentCount(index)
    if enchantCount ~= 0 then
        for i = 1, enchantCount do
            local enchantId = inventory:getItemStackEnchantmentId(index, i)
            local enchantLv = inventory:getItemStackEnchantmentLv(index, i)
            table.insert(enchantList, { enchantId, enchantLv })
        end
    end
    return enchantList
end

function ItemEnchantment:appendEnchantment(enchantList, appendList)
    for _, append in pairs(appendList) do
        local replace = false
        for _, enchant in pairs(enchantList) do
            if enchant[1] == append[1] and enchant[2] <= append[2] then
                enchant[2] = append[2]
                replace = true
                break
            end
        end
        if not replace then
            table.insert(enchantList, append)
        end
    end
end

ItemPotionEffect = {}

function ItemPotionEffect:getPotionEffect(itemId)
    return PotionEffect[tostring(itemId)]
end

ItemHelper = {}

---判断是否世界层是否能生成某个道具
function ItemHelper:canSpawnEntity(itemId)
    local item = Item.getItemById(itemId)
    if not item then
        return true, ""
    end
    local class = item:getClassName()
    if class == "ItemPickaxe" or class == "ItemAxe" or class == "ItemArmor" or class == "ItemArrow" or
            itemId == ItemID.SHEARS or ItemMapping:getOldItemId(itemId) == ItemID.SWORD_WOOD then
        ---工具/剪刀/装备/木剑/箭 不能生成到世界上
        return false, class
    end
    return true, class
end

---判断是否能丢弃某个道具
function ItemHelper:canDropItem(player, itemId)
    local canDrop, class = ItemHelper:canSpawnEntity(itemId)
    if not canDrop then
        return false
    end
    if class ~= "ItemSword" then
        ---不是剑就可以丢
        return true
    end
    local inv = player:getInventory()
    local swordCount = 0
    for index = 0, 35 do
        local info = inv:getItemStackInfo(index)
        if info.id ~= 0 then
            local item = Item.getItemById(info.id)
            if item and item:getClassName() == "ItemSword" then
                swordCount = swordCount + 1
            end
        end
    end
    if swordCount <= 1 then
        LuaTimer:schedule(function()
            if player:checkReady() then
                player:tryAddItem(ItemID.SWORD_WOOD, 1)
            end
        end, 100)
    end
    return true
end

---捡完道具根据装扮做替换
function ItemHelper:tryChangePickUpItem(player, itemId)
    local inv = player:getInventory()
    local item = Item.getItemById(itemId)
    if not item then
        return
    end
    local oldItemId
    local class = item:getClassName()
    if class == "ItemBlock" and itemId > 2000 then
        ---自定义方块需要-1000
        oldItemId = ItemMapping:getOldItemId(itemId - 1000)
    else
        oldItemId = ItemMapping:getOldItemId(itemId)
    end
    if class == "ItemSword" or class == "ItemBow" then
        for index = 0, 35 do
            local info = inv:getItemStackInfo(index)
            if info.id == itemId then
                ---武器类需要替换成对应的装扮并且加上还原附魔
                local enchantList = ItemEnchantment:getItemEnchantmentList(inv, index)
                ---删除队伍的增益
                SwordItemGain:removeSwordGain(enchantList)
                ---删除火焰附魔特权
                FireSwordPrivilege:removeSwordGain(enchantList)
                inv:decrStackSize(index, info.num)
                player:tryAddItem(oldItemId, info.num, 0, enchantList)
            end
        end
    else
        local dressId = player:tryItemId2DressId(oldItemId)
        if dressId == itemId then
            ---装扮跟捡到的道具相同，不需要换
            return
        end
        for index = 0, 35 do
            local info = inv:getItemStackInfo(index)
            if info.id == itemId then
                inv:decrStackSize(index, info.num)
                player:tryAddItem(oldItemId, info.num)
                break
            end
        end
    end
end